import { prisma } from '@/lib/prisma'

const STARTING_COINS = 10000

export type LeaderboardEntry = {
  rank: number
  id: string
  name: string
  coins: number
  heldCoins: number
  netWorth: number
  profit: number
  profitPct: number
  totalVolume: number
  betCount: number
  activeBetCount: number
  wins: number
  losses: number
}

export async function getLeaderboard(): Promise<LeaderboardEntry[]> {
  const [users, bets] = await Promise.all([
    prisma.user.findMany({
      select: {
        id: true,
        name: true,
        coins: true,
        heldCoins: true,
      },
    }),
    prisma.bet.findMany({
      select: {
        userName: true,
        coins: true,
        choice: true,
        market: {
          select: {
            resolved: true,
            outcome: true,
          },
        },
      },
    }),
  ])

  const statsByName = new Map<
    string,
    Pick<LeaderboardEntry, 'totalVolume' | 'betCount' | 'activeBetCount' | 'wins' | 'losses'>
  >()

  for (const bet of bets) {
    const stats = statsByName.get(bet.userName) || {
      totalVolume: 0,
      betCount: 0,
      activeBetCount: 0,
      wins: 0,
      losses: 0,
    }

    stats.totalVolume += bet.coins
    stats.betCount += 1

    if (!bet.market.resolved) {
      stats.activeBetCount += 1
    } else if (bet.market.outcome === bet.choice) {
      stats.wins += 1
    } else {
      stats.losses += 1
    }

