const { Client } = require('pg')

async function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms))
}

async function connectWithRetry(retries = 5) {
  let lastError

  for (let attempt = 1; attempt <= retries; attempt += 1) {
    const client = new Client({ connectionString: process.env.DATABASE_URL })

    try {
      await client.connect()
      return client
    } catch (error) {
      lastError = error
      try {
        await client.end()
      } catch {}
      if (attempt < retries) {
        await sleep(attempt * 1500)
      }
    }
  }

  throw lastError
}

async function main() {
  const client = await connectWithRetry()

  try {
    await client.query('BEGIN')
    await client.query('DELETE FROM "PriceHistory"')
    await client.query('DELETE FROM "Bet"')
    await client.query('DELETE FROM "Market"')
    await client.query('UPDATE "User" SET "heldCoins" = 0 WHERE "heldCoins" <> 0')
    await client.query('COMMIT')

    const counts = {}
    for (const table of ['User', 'Market', 'Bet', 'PriceHistory']) {
      const result = await client.query(`SELECT COUNT(*)::int AS count FROM "${table}"`)
      counts[table] = result.rows[0].count
    }

    console.log(JSON.stringify(counts, null, 2))
  } catch (error) {
    await client.query('ROLLBACK')
    throw error
  } finally {
    await client.end()
  }
}

main().catch((error) => {
  console.error(error)
  process.exit(1)
})
