'use client'

import { useState } from 'react'
import Link from 'next/link'
import { Badge } from '@/components/ui/badge'
import { Bookmark, Share2, TrendingUp } from 'lucide-react'
import type { MarketSummary } from '@/lib/market-types'

interface MarketCardProps {
  market: MarketSummary
  onQuickBet?: (marketId: string, choice: 'YES' | 'NO') => void
}

export function MarketCard({ market, onQuickBet }: MarketCardProps) {
  const [bookmarked, setBookmarked] = useState(false)
  const [copied, setCopied] = useState(false)
  const endDateStr = new Date(market.endDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
  const isResolved = market.resolved

  const yesLabel = market.optionYesLabel || 'Yes'
  const noLabel = market.optionNoLabel || 'No'

  const shareMarket = async () => {
    const url = `${window.location.origin}/market/${market.id}`
    if (navigator.share) {
      await navigator.share({ title: market.title, url })
      return
    }
    await navigator.clipboard.writeText(url)
    setCopied(true)
    setTimeout(() => setCopied(false), 1200)
  }

  return (
    <div className="bg-[#161b22] border border-[#30363d] rounded-lg overflow-hidden hover:border-[#484f58] transition-all group">
      {/* Header */}
      <Link href={`/market/${market.id}`} className="block p-3 pb-2">
        <div className="flex items-start gap-3">
          {/* Generic Icon */}
          <div className="w-10 h-10 rounded-lg bg-[#21262d] flex items-center justify-center shrink-0">
            <TrendingUp className="w-5 h-5 text-[#3fb950]" />
          </div>
          {/* Title */}
          <div className="flex-1 min-w-0">
            <h3 className="text-sm font-semibold text-white leading-tight line-clamp-2 group-hover:text-[#58a6ff] transition-colors">
              {market.title}
            </h3>
          </div>
        </div>
      </Link>

      {/* Outcome Rows */}
      <div className="px-3 space-y-1.5">
        {/* Option A Row */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2 min-w-0">
            <span className="text-xs text-[#8b949e] w-12 shrink-0">{endDateStr}</span>
            <span className="text-sm font-medium text-white truncate">{yesLabel}</span>
          </div>
          <div className="flex items-center gap-2 shrink-0">
            <span className="text-sm font-bold text-white">{market.yesPrice}%</span>
            {!isResolved && (
              <div className="flex items-center gap-1">
                <button
                  onClick={() => onQuickBet?.(market.id, 'YES')}
                  className="px-2.5 py-0.5 text-[11px] font-semibold rounded bg-[#238636]/20 text-[#3fb950] border border-[#238636]/30 hover:bg-[#238636]/30 transition-colors"
                >
                  {yesLabel}
                </button>
                <button
                  onClick={() => onQuickBet?.(market.id, 'NO')}
                  className="px-2.5 py-0.5 text-[11px] font-semibold rounded bg-[#da3633]/20 text-[#f85149] border border-[#da3633]/30 hover:bg-[#da3633]/30 transition-colors"
                >
                  {noLabel}
                </button>
              </div>
            )}
            {isResolved && (
              <Badge className={`text-[10px] h-5 ${market.outcome === 'YES' ? 'bg-[#238636]/20 text-[#3fb950]' : 'bg-[#da3633]/20 text-[#f85149]'}`}>
                {market.outcome === 'YES' ? yesLabel : noLabel}
              </Badge>
            )}
          </div>
        </div>

        {/* Option B Row */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2 min-w-0">
            <span className="text-xs text-[#8b949e] w-12 shrink-0">{endDateStr}</span>
            <span className="text-sm font-medium text-white truncate">{noLabel}</span>
          </div>
          <div className="flex items-center gap-2 shrink-0">
            <span className="text-sm font-bold text-white">{market.noPrice}%</span>
            {!isResolved && (
              <div className="flex items-center gap-1">
                <button
                  onClick={() => onQuickBet?.(market.id, 'YES')}
                  className="px-2.5 py-0.5 text-[11px] font-semibold rounded bg-[#238636]/20 text-[#3fb950] border border-[#238636]/30 hover:bg-[#238636]/30 transition-colors"
                >
                  {yesLabel}
                </button>
                <button
                  onClick={() => onQuickBet?.(market.id, 'NO')}
                  className="px-2.5 py-0.5 text-[11px] font-semibold rounded bg-[#da3633]/20 text-[#f85149] border border-[#da3633]/30 hover:bg-[#da3633]/30 transition-colors"
                >
                  {noLabel}
                </button>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Footer */}
      <div className="flex items-center justify-between px-3 py-2 mt-2 border-t border-[#21262d]">
        <div className="flex items-center gap-2 text-[11px] text-[#8b949e]">
          <span>${(market.volume / 1000).toFixed(1)}K Vol.</span>
          <span>·</span>
          <span className="text-[#3fb950]">LMSR</span>
        </div>
        <div className="flex items-center gap-1">
          <button
            onClick={() => setBookmarked(!bookmarked)}
            className={`p-1 rounded transition-colors ${bookmarked ? 'text-[#58a6ff]' : 'text-[#484f58] hover:text-[#8b949e]'}`}
            title="Bookmark"
          >
            <Bookmark className={`w-3.5 h-3.5 ${bookmarked ? 'fill-current' : ''}`} />
          </button>
          <button
            onClick={shareMarket}
            className="p-1 rounded text-[#484f58] hover:text-[#8b949e] transition-colors"
            title={copied ? 'Copied' : 'Share'}
          >
            <Share2 className="w-3.5 h-3.5" />
          </button>
        </div>
      </div>
    </div>
  )
}

