import type { Bet } from '@prisma/client'
import { calculateLMSRPrice, DEFAULT_LIQUIDITY } from '@/lib/pricing'

export type MarketShareData = {
  id: string
  title: string
  description: string
  category: string
  resolved: boolean
  outcome: string | null
  optionYesLabel: string
  optionNoLabel: string
  endDate: Date
  liquidity: number | null
  bets: Pick<Bet, 'choice' | 'coins'>[]
}

export function getMarketShareStats(market: MarketShareData) {
  const yesVolume = market.bets
    .filter((bet) => bet.choice === 'YES')
    .reduce((sum, bet) => sum + bet.coins, 0)
  const noVolume = market.bets
    .filter((bet) => bet.choice === 'NO')
    .reduce((sum, bet) => sum + bet.coins, 0)
  const volume = yesVolume + noVolume
  const { yesPrice, noPrice } = calculateLMSRPrice(
    yesVolume,
    noVolume,
    market.liquidity || DEFAULT_LIQUIDITY
  )

  return {
    yesPrice: Math.round(yesPrice * 100),
    noPrice: Math.round(noPrice * 100),
    volume,
    betCount: market.bets.length,
  }
}

export function formatCompactNumber(value: number) {
  return new Intl.NumberFormat('en-US', {
    notation: 'compact',
    maximumFractionDigits: 1,
  }).format(value)
}

export function formatShareDescription(market: MarketShareData) {
  const stats = getMarketShareStats(market)
  const resolvedText = market.resolved && market.outcome
    ? `Resolved: ${market.outcome === 'YES' ? market.optionYesLabel : market.optionNoLabel}. `
    : ''
  const oddsText = `${market.optionYesLabel} ${stats.yesPrice}% / ${market.optionNoLabel} ${stats.noPrice}%`
  const volumeText = `${formatCompactNumber(stats.volume)} coins volume`
  const body = market.description.trim()

  return `${resolvedText}${oddsText}. ${volumeText}. ${body}`.slice(0, 220)
}

