import type { Metadata } from 'next'
import { prisma } from '@/lib/prisma'
import { formatShareDescription } from '@/lib/market-share'
import MarketClient from './market-client'

type MarketPageProps = {
  params: Promise<{ id: string }>
}

export async function generateMetadata({ params }: MarketPageProps): Promise<Metadata> {
  const { id } = await params
  const market = await prisma.market.findUnique({
    where: { id },
    select: {
      title: true,
      description: true,
      category: true,
      imageUrl: true,
      resolved: true,
      outcome: true,
      optionYesLabel: true,
      optionNoLabel: true,
      endDate: true,
      liquidity: true,
      bets: {
        select: {
          choice: true,
          coins: true,
        },
      },
    },
  })

  if (!market) {
    return {
      title: 'Market not found | 12Polymarket',
    }
  }

  const description = formatShareDescription({ id, ...market })
  const imageUrl = `/api/og/market/${id}`
  const pageUrl = `/market/${id}`

  return {
    title: `${market.title} | 12Polymarket`,
    description,
    alternates: {
      canonical: pageUrl,
    },
    openGraph: {
      title: market.title,
      description,
      type: 'website',
      siteName: '12Polymarket',
      url: pageUrl,
      images: [{ url: imageUrl, width: 1200, height: 630, alt: `${market.title} market odds` }],
    },
    twitter: {
      card: 'summary_large_image',
      title: market.title,
      description,
      images: [imageUrl],
    },
  }
}

export default function MarketPage() {
  return <MarketClient />
}

