export const dynamic = 'force-dynamic'

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { calculateLMSRPrice, DEFAULT_LIQUIDITY } from '@/lib/pricing'
import { getSessionUser } from '@/lib/auth'

export async function POST(request: NextRequest) {
  try {
    const sessionUser = await getSessionUser()
    if (!sessionUser) {
      return NextResponse.json({ error: 'Please sign in to place a bet' }, { status: 401 })
    }

    const body = await request.json()
    const { marketId, coins, choice } = body
    const userName = sessionUser.name

    if (!marketId || !['YES', 'NO'].includes(choice) || !Number.isFinite(Number(coins)) || Number(coins) <= 0) {
      return NextResponse.json({ error: 'Invalid bet request' }, { status: 400 })
    }

    const market = await prisma.market.findUnique({
      where: { id: marketId },
      select: {
        id: true,
        resolved: true,
        liquidity: true,
        bets: {
          select: {
            choice: true,
            coins: true,
          },
        },
      },
    })

    if (!market) {
      return NextResponse.json({ error: 'Market not found' }, { status: 404 })
    }

    if (market.resolved) {
      return NextResponse.json({ error: 'Market already resolved' }, { status: 400 })
    }

    const user = await prisma.user.findUnique({ 
      where: { id: sessionUser.id },
      select: { id: true, coins: true, heldCoins: true },
    })
    if (!user) {
      return NextResponse.json({ error: 'User not found' }, { status: 401 })
    }

    const betCoins = Number(coins)

    if (user.coins < betCoins) {
      return NextResponse.json(
        { error: `Insufficient coins. You have ${user.coins.toLocaleString()} available.` },
        { status: 400 }
      )
    }

    const yesVolume = market.bets
      .filter((b) => b.choice === 'YES')
      .reduce((sum, b) => sum + b.coins, 0)
    const noVolume = market.bets
      .filter((b) => b.choice === 'NO')
      .reduce((sum, b) => sum + b.coins, 0)

    const liquidity = market.liquidity || DEFAULT_LIQUIDITY
    const { yesPrice: currentYesPrice, noPrice: currentNoPrice } =
      calculateLMSRPrice(yesVolume, noVolume, liquidity)

    const betPrice = choice === 'YES' ? currentYesPrice : currentNoPrice

    // Execute in transaction for consistency
    await prisma.$transaction([
      prisma.user.update({
        where: { id: user.id },
        data: {
          coins: user.coins - betCoins,
          heldCoins: user.heldCoins + betCoins,
        },
      }),
      prisma.bet.create({
        data: {
          marketId,
          userName,
          coins: betCoins,
          choice,
          price: betPrice,
        },
      }),
    ])

    // Update price history
    const newYesVolume = yesVolume + (choice === 'YES' ? betCoins : 0)
    const newNoVolume = noVolume + (choice === 'NO' ? betCoins : 0)

    const { yesPrice: newYesPrice, noPrice: newNoPrice } =
      calculateLMSRPrice(newYesVolume, newNoVolume, liquidity)

    await prisma.priceHistory.create({
      data: {
        marketId,
        yesPrice: newYesPrice,
        noPrice: newNoPrice,
      },
    })

    return NextResponse.json({ success: true })
  } catch {
    return NextResponse.json({ error: 'Failed to place bet' }, { status: 500 })
  }
}

